+// ============================================================================
+// Shell escape tests
+// ============================================================================
+
+func TestShellEscape_SafeStrings(t *testing.T) {
+	tests := []struct {
+		input    string
+		expected string
+	}{
+		{"simple", "simple"},
+		{"ISSUE-123", "ISSUE-123"},
+		{"bv-qjc.1", "bv-qjc.1"},
+		{"test_id", "test_id"},
+		{"A1B2C3", "A1B2C3"},
+		{"issue:123", "issue:123"},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.input, func(t *testing.T) {
+			got := shellEscape(tt.input)
+			if got != tt.expected {
+				t.Errorf("shellEscape(%q) = %q; want %q", tt.input, got, tt.expected)
+			}
+		})
+	}
+}
+
+func TestShellEscape_UnsafeStrings(t *testing.T) {
+	tests := []struct {
+		input    string
+		expected string
+	}{
+		{"has space", "'has space'"},
+		{"with'quote", "'with'\"'\"'quote'"},
+		{"$variable", "'$variable'"},
+		{"`command`", "'`command`'"},
+		{"semi;colon", "'semi;colon'"},
+		{"pipe|char", "'pipe|char'"},
+		{"less<greater>", "'less<greater>'"},
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.input, func(t *testing.T) {
+			got := shellEscape(tt.input)
+			if got != tt.expected {
+				t.Errorf("shellEscape(%q) = %q; want %q", tt.input, got, tt.expected)
+			}
+		})
+	}
+}
+
+func TestIsShellSafe(t *testing.T) {
+	safeStrings := []string{
+		"simple",
+		"ISSUE-123",
+		"test_id",
+		"file.txt",
+		"a:b",
+	}
+	unsafeStrings := []string{
+		"has space",
+		"with'quote",
+		"$var",
+		"",
+		"semi;colon",
+	}
+
+	for _, s := range safeStrings {
+		if !isShellSafe(s) {
+			t.Errorf("isShellSafe(%q) = false; want true", s)
+		}
+	}
+	for _, s := range unsafeStrings {
